class Solution {
    public int countGoodStrings(int low, int high, int zero, int one) {
        int mod = (int) 1e9 + 7;
        long[] dp = new long[high + 1];
        dp[0] = 1;
        long res = 0;
        for (int i = 1; i <= high; i++) {
            if (i >= zero) dp[i] += dp[i - zero];
            if (i >= one) dp[i] += dp[i - one];
            dp[i] %= mod;
        }
        for (int i = low; i <= high; i++) {
            res = (res + dp[i]) % mod;
        }
        return (int) res;
    }
}
